-------------------------------------------------------------------------------
-- delta views
-------------------------------------------------------------------------------

create view TravelService_Airline_delta as
select
    t.AirlineID,
    d.AirlinePicURL,
    d.CurrencyCode_code,
    d.Name,
    t.is_deleted,
    t.last_modified
from sap_fe_cap_travel_Airline_tracking t
    left outer join TravelService_Airline d on d.AirlineID = t.AirlineID;

create view TravelService_Airport_delta as
select
    t.AirportID,
    d.City,
    d.CountryCode_code,
    d.Name,
    t.is_deleted,
    t.last_modified
from sap_fe_cap_travel_Airport_tracking t
    left outer join TravelService_Airport d on d.AirportID = t.AirportID;

create view TravelService_Booking_delta as
select
    t.BookingUUID,
    d.BookingDate,
    d.BookingID,
    d.BookingStatus_code,
    d.ConnectionID,
    d.CurrencyCode_code,
    d.FlightDate,
    d.FlightPrice,
    d.LastChangedAt,
    d.LastChangedBy,
    d.createdAt,
    d.createdBy,
    d.to_Carrier_AirlineID,
    d.to_Customer_CustomerID,
    d.to_Travel_TravelUUID,
    t.is_deleted,
    t.last_modified
from sap_fe_cap_travel_Booking_tracking t
    left outer join TravelService_Booking d on d.BookingUUID = t.BookingUUID;

create view TravelService_BookingSupplement_delta as
