create view TravelService_Flight_delta as
select
    t.AirlineID,
    t.FlightDate,
    t.ConnectionID,
    d.CurrencyCode_code,
    d.MaximumSeats,
    d.OccupiedSeats,
    d.PlaneType,
    d.Price,
    t.is_deleted,
    t.last_modified
from sap_fe_cap_travel_Flight_tracking t
    left outer join TravelService_Flight d on d.AirlineID = t.AirlineID and d.FlightDate = t.FlightDate and d.ConnectionID = t.ConnectionID;

create view TravelService_FlightConnection_delta as
select
    t.ConnectionID,
    t.AirlineID,
    d.ArrivalTime,
    d.DepartureAirport_AirportID,
    d.DepartureTime,
    d.DestinationAirport_AirportID,
    d.Distance,
    d.DistanceUnit,
    t.is_deleted,
    t.last_modified
from sap_fe_cap_travel_FlightConnection_tracking t
    left outer join TravelService_FlightConnection d on d.ConnectionID = t.ConnectionID and d.AirlineID = t.AirlineID;

create view TravelService_Passenger_delta as
