from sap_fe_cap_travel_Travel_tracking t
    left outer join TravelService_Travel d on d.TravelUUID = t.TravelUUID;

create view TravelService_TravelAgency_delta as
select
    t.AgencyID,
    d.City,
    d.CountryCode_code,
    d.EMailAddress,
    d.Name,
